<script setup>
import { ref, computed, onMounted, onUnmounted } from 'vue';
import { useRouter } from 'vue-router';
import { useAuth } from '@/composables/useAuth';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import fallbackAvatar from '@/assets/IMG/suliusu.jpg';
import MessageNotification from './message/MessageNotification.vue';

gsap.registerPlugin(ScrollTrigger);

const router = useRouter();
const { isLoggedIn, userAvatar, checkAuth } = useAuth();
const avatarLoaded = ref(false);

// Logo SVG refs for scroll-driven spin
const logoSvg1 = ref(null);
const logoSvg2 = ref(null);
const logoSvg3 = ref(null);
let logoTweenCtx = null;

// 配置常量
const HDcont = 1900; // 滚动阈值，可在此处修改

const isScrolled = ref(false);
const isHovered = ref(false);
const shouldDelayBgHide = ref(false); // 背景延迟收起标志
let scrollListener = null;
let mouseEnterTimer = null;
let mouseLeaveTimer = null;
let delayTimer = null; // 背景延迟收起定时器

// 导航菜单相关状态
const activeMenuIndex = ref(-1); // 当前激活的菜单索引，-1表示未激活
const isDropdownVisible = ref(false); // 下拉菜单是否可见
const dropdownContent = ref(''); // 下拉菜单内容
const hoveredBtnIndex = ref(-1); // hover状态的按钮索引
const showUnderline = ref(false); // 控制白色横条显示（需要等待背景加载完成）

// 搜索框相关状态
const isSearchFocused = ref(false);
const searchQuery = ref('');
const searchInputRef = ref(null);

const onSearchFocus = () => {
  isSearchFocused.value = true;
};

const onSearchBlur = () => {
  setTimeout(() => {
    const scrollTop = window.scrollY || document.documentElement.scrollTop;
    isSearchFocused.value = false;

    if (scrollTop <= HDcont && !isHovered.value && !isDropdownVisible.value) {
      shouldDelayBgHide.value = true;
      if (delayTimer) clearTimeout(delayTimer);
      delayTimer = setTimeout(() => {
        shouldDelayBgHide.value = false;
        delayTimer = null;
      }, 300);
    }
  }, 150);
};

const onSearchIconClick = () => {
  if (isSearchFocused.value) {
    if (searchQuery.value.trim()) {
      searchQuery.value = '';
    }
    searchInputRef.value?.blur();
  } else {
    searchInputRef.value?.focus();
  }
};

const onSearchSubmit = () => {
  if (searchQuery.value.trim()) {
    // 跳转到搜索页面，并携带搜索关键词
    router.push({
      name: 'search',
      query: { q: searchQuery.value.trim() }
    })
    searchQuery.value = ''
  } else {
    // 没有输入关键词，直接跳转到搜索页面
    router.push({ name: 'search' })
  }
}

// 计算属性：背景是否应该显示
const shouldShowBg = computed(() => {
  return isScrolled.value ||
         isHovered.value ||
         isDropdownVisible.value ||
         isSearchFocused.value ||
         shouldDelayBgHide.value;
});

// 菜单配置 - 包含高度信息
const menuItems = [
  { label: '资源总览', content: '这里是资源总览的内容区域', height: '600px' }, // 最高
  { label: '创作中心', content: '这里是创作中心的内容区域', height: '400px' }, // 保持当前高度
  { label: '关于我们', content: '这里是关于我们的内容区域', height: '500px' } // 中等高度
];

// 计算当前激活菜单的高度
const currentMenuHeight = computed(() => {
  if (activeMenuIndex.value >= 0 && activeMenuIndex.value < menuItems.length) {
    return menuItems[activeMenuIndex.value].height;
  }
  return '400px'; // 默认高度
});

// 监听页面滚动
const handleScroll = () => {
  const scrollTop = window.scrollY || document.documentElement.scrollTop;
  isScrolled.value = scrollTop > HDcont;
  
  // 如果滚动到内容区域，取消任何延迟收起
  if (isScrolled.value && delayTimer) {
    clearTimeout(delayTimer);
    delayTimer = null;
    shouldDelayBgHide.value = false;
  }
};

// 鼠标移入导航栏
const handleMouseEnter = () => {
  // 清除离开定时器（防止闪烁）
  if (mouseLeaveTimer) {
    clearTimeout(mouseLeaveTimer);
    mouseLeaveTimer = null;
  }
  
  // 取消背景延迟收起
  if (delayTimer) {
    clearTimeout(delayTimer);
    delayTimer = null;
  }
  shouldDelayBgHide.value = false;
  
  // 立即设置 hover 状态（背景会自动显示）
  isHovered.value = true;
  
  // 延迟显示横条，确保背景已经加载完成
  setTimeout(() => {
    showUnderline.value = true;
  }, 150);
};

// 鼠标移出导航栏
const handleMouseLeave = () => {
  // 清除进入定时器（如果还在延迟期内就移出）
  if (mouseEnterTimer) {
    clearTimeout(mouseEnterTimer);
    mouseEnterTimer = null;
  }
  
  // 立即隐藏横条
  showUnderline.value = false;
  
  // 立即取消 hover 状态（背景会根据其他状态决定是否隐藏）
  isHovered.value = false;
};

// 点击左侧标题回到顶部
const scrollToTop = () => {
  window.scrollTo({
    top: 0,
    behavior: 'smooth'
  });
};

// 处理菜单项点击
const handleMenuClick = (index) => {
  const menuItem = menuItems[index];
  
  if (!isDropdownVisible.value) {
    // 首次打开：播放展开动画
    activeMenuIndex.value = index;
    dropdownContent.value = menuItem.content;
    isDropdownVisible.value = true;
    showUnderline.value = true; // 确保横条显示
  } else {
    // 已打开：直接切换内容（不重新播放动画）
    if (activeMenuIndex.value !== index) {
      activeMenuIndex.value = index;
      dropdownContent.value = menuItem.content;
    }
  }
};

// 关闭下拉菜单
const closeDropdown = () => {
  // 清除之前的延迟定时器（防止重复执行）
  if (delayTimer) {
    clearTimeout(delayTimer);
    delayTimer = null;
  }
  
  const scrollTop = window.scrollY || document.documentElement.scrollTop;
  
  // 第一步：立即关闭选项卡（触发收起动画）
  isDropdownVisible.value = false;
  activeMenuIndex.value = -1;
  dropdownContent.value = '';
  showUnderline.value = false;
  
  // 第二步：判断是否需要延迟收起背景
  if (scrollTop <= HDcont && !isHovered.value) {
    // 在顶部区域且没有hover → 启动延迟，等待选项卡动画完成
    shouldDelayBgHide.value = true;
    
    delayTimer = setTimeout(() => {
      shouldDelayBgHide.value = false; // 300ms后收起背景
      delayTimer = null;
    }, 300); // 与选项卡动画时长保持一致
  }
  // 如果在内容区域或有hover，shouldDelayBgHide保持false
  // 背景会立即根据 isScrolled 或 isHovered 决定是否显示
};

// 处理按钮hover
const handleBtnHover = (index) => {
  hoveredBtnIndex.value = index;
};

// 处理按钮离开
const handleBtnLeave = () => {
  hoveredBtnIndex.value = -1;
};

// Logo SVG 滚动自转动画 —— num1z 范围内旋转，进入 num2z 后停止
const initLogoSpin = () => {
  const section = document.querySelector('#num1z');
  if (!section || !logoSvg1.value) return;

  logoTweenCtx = gsap.context(() => {
    gsap.to(logoSvg1.value, {
      rotation: 180,
      ease: 'none',
      scrollTrigger: {
        trigger: '#num1z',
        start: 'top top',
        end: 'bottom top',
        scrub: 0.5,
      },
    });
    gsap.to(logoSvg2.value, {
      rotation: -180,
      ease: 'none',
      scrollTrigger: {
        trigger: '#num1z',
        start: 'top top',
        end: 'bottom top',
        scrub: 0.5,
      },
    });
    gsap.to(logoSvg3.value, {
      rotation: 360,
      ease: 'none',
      scrollTrigger: {
        trigger: '#num1z',
        start: 'top top',
        end: 'bottom top',
        scrub: 0.5,
      },
    });
    gsap.to('.n1_logo .logo_text', {
      backgroundPositionX: '0%',
      ease: 'none',
      scrollTrigger: {
        trigger: '#num1z',
        start: 'top top',
        end: 'bottom top',
        scrub: 0.5,
      },
    });

  });
};

onMounted(() => {
  // 检查登录状态
  checkAuth();

  // 检查初始滚动位置
  const scrollTop = window.scrollY || document.documentElement.scrollTop;
  isScrolled.value = scrollTop > HDcont;

  scrollListener = window.addEventListener('scroll', handleScroll, { passive: true });

  initLogoSpin();
});

onUnmounted(() => {
  if (scrollListener) {
    window.removeEventListener('scroll', handleScroll);
  }
  if (mouseEnterTimer) {
    clearTimeout(mouseEnterTimer);
  }
  if (mouseLeaveTimer) {
    clearTimeout(mouseLeaveTimer);
  }
  if (delayTimer) {
    clearTimeout(delayTimer);
  }
  if (logoTweenCtx) {
    logoTweenCtx.revert();
    logoTweenCtx = null;
  }
});
</script>

<template>
    <section class="main" @mouseenter="handleMouseEnter" @mouseleave="handleMouseLeave">
        <div class="main_bg" :class="{ 'bg-visible': shouldShowBg }"></div>
        
        <!-- 左侧标题 -->
        <div class="navTag n1_logo" @click="scrollToTop">
          <p class="logo_text">Pixel - Vision</p>
          <svg ref="logoSvg1" t="1779498952979" class="icon" viewBox="0 0 1024 1024" version="1.1" xmlns="http://www.w3.org/2000/svg" p-id="3588" width="20" height="20"><path d="M427.20768 958.73536s137.42592-16.76288 194.80576-106.79808c18.49856-29.02016 39.61856-43.69408 60.33408-44.68736 58.33216-2.80576 35.24096 55.38304 40.29952 62.27968 4.29056 5.85216 13.93664 2.56 34.0992 6.22592 23.04 4.20352 34.33984 46.592-0.83968 73.25184-41.05728 31.09888-168.56064 99.44064-328.69888 9.728z" fill="#B8D390" p-id="3589"></path><path d="M127.4368 651.5456s-11.776-76.43648 86.79936-105.8816c20.40832 29.61408 16.6144 75.776 3.0976 108.99456-9.56928 23.552-26.16832 37.376-34.0992 40.48384-14.66368 6.26176-1.536 12.68736 15.49824 9.33888a196.44416 196.44416 0 0 0 65.1008-31.13984c16.85504-9.728 16.75264 17.12128 12.40064 37.376s-39.66976 60.53376-102.30272 40.48384c0 0-16.70144-6.25664-6.20032 9.33888s21.87776 60.35456-55.808 65.39776c0 0 4.31616-21.03808-27.89888-52.9408s1.88928-59.904 18.60096-52.9408c0 0 5.24288 1.29536 0-6.22592-4.33152-6.18496-48.04608-0.41984-71.30112-18.68288-14.25408-11.19744-23.41376-38.2208-24.10496-45.68064-3.83488-41.5488 17.88928-13.48096 17.92-13.48608s37.15584 26.91072 49.60256 28.02688 7.72608-2.87232 3.0976-6.23104S0.55296 610.92864 22.016 530.09408c96.96256-6.28736 99.2 112.128 99.2 112.128s3.62496 19.34336 6.2208 9.32352z" fill="#77B26B" p-id="3590"></path><path d="M332.03712 424.2176s67.00544 73.50272 55.808 143.24736c-8.96512 55.7824-64.6912 57.344-80.59904 68.51072-10.80832 7.59808-34.27328-39.59808-27.68896-92.16a126.83776 126.83776 0 0 1 33.88928-72.86272s3.93216-4.02432 6.20032 3.11296a275.36896 275.36896 0 0 1 6.20032 37.376c0.58368 3.98848 2.2016 13.51168 6.20032 15.56992 2.34496 0.2304 6.39488-6.74304 6.20032-12.45696-0.13824-4.096-0.768-21.66784-3.10272-40.48384-3.18976-25.69728-7.85408-53.4016-3.10784-49.85344z" fill="#6D8638" p-id="3591"></path><path d="M139.83744 277.85728s16.77824-59.74528 68.1984-40.48384c36.41344 13.62432 25.