        </div>

        <!-- 中部资源导航 -->
        <section class="navTag n2_link">
            <div 
                v-for="(item, index) in menuItems" 
                :key="index"
                class="n2_btn_wrapper"
                @mouseenter="handleBtnHover(index)"
                @mouseleave="handleBtnLeave"
            >
                <div 
                    class="n2_btn" 
                    :class="{ 'active': activeMenuIndex === index }"
                    @click="handleMenuClick(index)"
                >
                    {{ item.label }}
                </div>
                <div 
                    class="underline" 
                    :class="{ 
                        'visible': activeMenuIndex === index,
                        'hover-visible': hoveredBtnIndex === index && activeMenuIndex !== index && showUnderline
                    }"
                ></div>
            </div>
        </section>

        <!-- 右侧个人选项 -->
        <section class="navTag n3_cont">
            <div class="search_wrapper" :class="{ 'is-focused': isSearchFocused }">
                <input
                    ref="searchInputRef"
                    v-model="searchQuery"
                    type="text"
                    class="search_input"
                    :placeholder="isSearchFocused ? 'let me see see' : '让我CanCan'"
                    @focus="onSearchFocus"
                    @blur="onSearchBlur"
                    @keyup.enter="onSearchSubmit"
                />
                <div class="search_action" :class="{ 'is-active': isSearchFocused }" @click="onSearchIconClick">
                    <svg v-if="!isSearchFocused" viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="#fff" stroke-width="2.5">
                        <circle cx="11" cy="11" r="8"/>
                        <path d="M21 21l-4.35-4.35"/>
                    </svg>
                    <svg v-else viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="#fff" stroke-width="2.5">
                        <path d="M5 12h14M13 5l7 7-7 7"/>
                    </svg>
                </div>
            </div>
            <!-- 消息通知组件 -->
            <MessageNotification />
            <div v-if="!isLoggedIn" class="login_btn" @click="$router.push('/login')">JoinUs</div>
            <div v-else class="avatar_pill" @click="$router.push('/profile/me')">
                <div class="avatar_stack">
                    <img :src="fallbackAvatar" class="user_avatar avatar_bg" alt="" />
                    <img
                        v-show="avatarLoaded"
                        :src="userAvatar"
                        class="user_avatar avatar_fg"
                        alt=""
                        @load="avatarLoaded = true"
                        @error="avatarLoaded = false"
                    />
                </div>
                <span class="pill_meta">
                    <span class="pill_label">me</span>
                    <span class="online_dot"></span>
                </span>
            </div>
        </section>
    </section>

    <!-- 玻璃遮罩层 - 独立于导航栏 -->
    <transition name="overlay">
        <div v-if="isDropdownVisible" class="overlay" @click="closeDropdown"></div>
    </transition>

    <!-- 下拉选项卡 - 独立于导航栏 -->
    <transition name="dropdown">
        <div v-if="isDropdownVisible" class="dropdown-menu" :style="{ height: currentMenuHeight }">
            <div class="dropdown-content">
                {{ dropdownContent }}
            </div>
        </div>
    </transition>

</template>

<style scoped>
.main{
    position:fixed;
    z-index: 1000;
    width: 100%;
    height: 100px;
    padding-bottom: 50px;

    display: flex;
    padding:0 5%;
}

/* 独立的黑色背景色块 */
.main_bg{
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 50px;
    background-color: rgba(0, 0, 0, 0.95);
    backdrop-filter: blur(10px);
    box-shadow: 0 4px 30px rgba(0, 0, 0, 0.3);
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    z-index: -1;
    
    /* 默认状态：在可视区域外 */
    transform: translateY(-100%);
    transition: transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

/* 显示状态：滑入可视区域 */
.main_bg.bg-visible{
    transform: translateY(0);
}

.navTag{
    /* border:2px solid #8edc93; */
    height: 100%;
    position: relative;
    z-index: 1; /* 确保文字在背景之上 */
}

.n1_logo{
    font-family: "华文琥珀";
    width:200px;
    height: 50px;
    line-height: 50px;
    color:#fff;
    font-size: clamp(20px,30px,50px) ;
    margin-right: 20px;
    cursor: pointer;
